// RGB LED Functions
const uint8_t R_PIN = 5;
const uint8_t G_PIN = 6;
const uint8_t B_PIN = 9;

void init_rgb_led() {
    pinMode(R_PIN, OUTPUT);
    pinMode(G_PIN, OUTPUT);
    pinMode(B_PIN, OUTPUT);
}

void set_rgb_led(uint8_t r, uint8_t g, uint8_t b) { // from 0 to 255
    analogWrite(R_PIN, r);
    analogWrite(G_PIN, g);
    analogWrite(B_PIN, b);
}

void initButtons() {

  //Serial.begin(9615);
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  pinMode(BUTTON_2_PIN, INPUT_PULLUP);

}

bool page = true;

void buttons() {

  int buttonState = digitalRead(BUTTON_PIN);
  int button2State = digitalRead(BUTTON_2_PIN);

  //Serial.println(buttonState);

  if (buttonState == LOW) {
    lcd.clear();
    page = false;
  }

  if (button2State == LOW) {
    page = true;
  }

//-------------------------

  if (page == true) {
    dht11();
  }

  if (page == false) {
    water();
  }

}

#include "DHT.h"

#define DHTPIN 2 
#define DHTTYPE DHT11   // DHT 11

DHT dht(DHTPIN, DHTTYPE);

void initDHT() {
  Serial.begin(9615);
  dht.begin();
}

void dht11() {
  // Wait a few seconds between measurements.
  delay(2000);

  // Reading temperature or humidity takes about 250 milliseconds!
  // Sensor readings may also be up to 2 seconds 'old' (its a very slow sensor)
  float h = dht.readHumidity();
  // Read temperature as Celsius (the default)
  float t = dht.readTemperature();

  // Check if any reads failed and exit early (to try again).
  if (isnan(h) || isnan(t)) {
    Serial.println(F("Failed to read from DHT sensor!"));
    return;

  }
  lcd.clear(); 
  lcd.setCursor(0, 0);
  lcd.print(F("Humidity: "));

  lcd.setCursor(10, 0);
  lcd.print(h * 2);

  lcd.setCursor(15, 0);
  lcd.print("%");
//_______________________________
  lcd.setCursor(0, 1);
  lcd.print(F("Temp: "));

  lcd.setCursor(6, 1);
  lcd.print(t * 2);

  lcd.setCursor(12, 1);
  lcd.print("C");

}

void initWater() {

}

void water() {
  int value = analogRead(A2);  // Reading the analog value from pin A2

  value = value / 10;

  if (value < 20) {
      lcd.clear();

      lcd.setCursor(0, 0);
      lcd.print("Water: ");

      lcd.setCursor(7, 0);
      lcd.print(value);

      lcd.setCursor(10, 0);
      lcd.print("%");

      lcd.setCursor(0, 1);
      lcd.print("No water");
      set_rgb_led(255, 0, 0); // red
      delay(200);
    // Displaying the text "No water"

  } else if (value >= 20 && value < 50) {
    lcd.clear();

    lcd.setCursor(0, 0);
    lcd.print("Water: ");

    lcd.setCursor(7, 0);
    lcd.print(value);

    lcd.setCursor(10, 0);
    lcd.print("%");

    lcd.setCursor(0, 1);
    lcd.print("Low water");
    set_rgb_led(255, 128, 0); // orange
    delay(200);
    // Displaying the text "Low"

  } else if (value >= 50 && value < 80) {
    lcd.clear();

    lcd.setCursor(0, 0);
    lcd.print("Water: ");

    lcd.setCursor(7, 0);
    lcd.print(value);

    lcd.setCursor(10, 0);
    lcd.print("%");

    lcd.setCursor(0, 1);
    lcd.print("Medium water");
    set_rgb_led(255, 255, 0); // yellow
    delay(200);
   // Displaying the text "Medium"

  } else if (value >= 80) {
    lcd.clear();

    lcd.setCursor(0, 0);
    lcd.print("Water: ");

    lcd.setCursor(7, 0);
    lcd.print(value - 2);

    lcd.setCursor(10, 0);
    lcd.print("%");

    lcd.setCursor(0, 1);
    lcd.print("High water");  
    set_rgb_led(0, 255, 0); // green
    delay(200);
    // Displaying the text "High"
    }
}
